-- Step 1: Delete ALL old email drafts (templates with 100-128 chars are useless)
DELETE FROM email_drafts WHERE LENGTH(body) < 500;

-- Step 2: Delete remaining drafts from old sessions (EPM test drafts, old PETLIFE test)
DELETE FROM email_drafts WHERE company IN ('FAGOR', 'FAGOR campa', 'PETLIFE 360', 'EPM Construcciones SA de CV');

-- Step 3: Verify PET LIFE 360 company exists - insert if not
INSERT IGNORE INTO companies (id, name, slug, industry, plan, isActive, createdAt, updatedAt)
VALUES (10001, 'PET LIFE 360', 'pet-life-360', 'Productos y Servicios para Mascotas', 'pro', 1, NOW(), NOW());

-- Step 4: Update FAGOR to have proper data (use existing id 90001)
UPDATE companies SET 
  name = 'FAGOR Automation',
  industry = 'Automatización Industrial y CNC',
  isActive = 1,
  updatedAt = NOW()
WHERE id = 90001;

-- Step 5: Remove duplicate FAGOR entries
DELETE FROM companies WHERE id = 60001;

-- Step 6: Remove placeholder/demo companies
DELETE FROM companies WHERE id IN (1, 2, 3, 4) AND name IN ('Demo Company', 'Acme Corporation', 'Startup Inc', 'Global Services LLC');

